using UnityEngine;
using System;

[Serializable]
public class PlayerStats
{
    public int level = 1;

    public int maxHealth = 100;
    public int currentHealth = 100;

    public int baseDamage = 10;
    public float critChance = 0.1f;
    public float critMultiplier = 2.0f;

    public int softCurrency = 0;
    public int hardCurrency = 0;

    public int damageBonusFlat = 0;
    public float damageBonusMultiplier = 0f;

    public int healthBonusFlat = 0;

    public void ClampAndRecompute()
    {
        int mh = Mathf.Max(1, maxHealth + healthBonusFlat);
        maxHealth = mh;
        currentHealth = Mathf.Clamp(currentHealth, 0, maxHealth);

        level = Mathf.Max(1, level);
        baseDamage = Mathf.Max(0, baseDamage);
        softCurrency = Mathf.Max(0, softCurrency);
        hardCurrency = Mathf.Max(0, hardCurrency);

        critChance = Mathf.Clamp01(critChance);
        critMultiplier = Mathf.Max(1f, critMultiplier);

        damageBonusFlat = Mathf.Max(0, damageBonusFlat);
        damageBonusMultiplier = Mathf.Max(0f, damageBonusMultiplier);
        healthBonusFlat = Mathf.Max(0, healthBonusFlat);
    }
}

public enum CurrencyType
{
    Soft,
    Hard
}

public enum DamageType
{
    Physical,
    Magical,
    True
}

public class PlayerManager : MonoBehaviour
{
    [Header("Public Player Stats (stored in public variables)")]
    public PlayerStats stats = new PlayerStats();

    [Header("Damage Tuning")]
    public float levelDamageScaling = 0.05f;
    public bool useRandomCrit = true;

    [Header("Persistence")]
    public bool loadOnStart = true;
    public bool saveOnQuit = true;

    public event Action<int, int> OnHealthChanged;
    public event Action<int, int> OnCurrencyChanged;

    const string SaveKey = "PLAYER_SAVE_V1";

    void Awake()
    {
        if (loadOnStart)
            Load();
        stats.ClampAndRecompute();
        RaiseAll();
    }

    void OnApplicationQuit()
    {
        if (saveOnQuit) Save();
    }

    void OnApplicationPause(bool pause)
    {
        if (pause && saveOnQuit) Save();
    }

    public int CalculateOutgoingDamage(int enemyDefense = 0, DamageType damageType = DamageType.Physical, bool forceCrit = false)
    {
        stats.ClampAndRecompute();

        float levelScale = 1f + (Mathf.Max(0, stats.level - 1) * levelDamageScaling);
        float dmg = (stats.baseDamage + stats.damageBonusFlat) * (1f + stats.damageBonusMultiplier) * levelScale;

        if (damageType != DamageType.True)
        {
            float def = Mathf.Max(0, enemyDefense);
            float reduction = def / (def + 100f);
            dmg *= (1f - reduction);
        }

        bool crit = forceCrit || (useRandomCrit && UnityEngine.Random.value < stats.critChance);
        if (crit) dmg *= stats.critMultiplier;

        return Mathf.Max(0, Mathf.FloorToInt(dmg));
    }

    public int ApplyIncomingDamage(int rawDamage, int armor = 0, DamageType damageType = DamageType.Physical)
    {
        stats.ClampAndRecompute();

        int dmg = Mathf.Max(0, rawDamage);
        if (damageType != DamageType.True)
        {
            float def = Mathf.Max(0, armor);
            float reduction = def / (def + 100f);
            dmg = Mathf.FloorToInt(dmg * (1f - reduction));
        }

        int before = stats.currentHealth;
        stats.currentHealth = Mathf.Clamp(stats.currentHealth - dmg, 0, stats.maxHealth);
        if (before != stats.currentHealth)
            OnHealthChanged?.Invoke(stats.currentHealth, stats.maxHealth);

        return dmg;
    }

    public void Heal(int amount)
    {
        stats.ClampAndRecompute();
        int before = stats.currentHealth;
        stats.currentHealth = Mathf.Clamp(stats.currentHealth + Mathf.Max(0, amount), 0, stats.maxHealth);
        if (before != stats.currentHealth)
            OnHealthChanged?.Invoke(stats.currentHealth, stats.maxHealth);
    }

    public bool IsDead()
    {
        return stats.currentHealth <= 0;
    }

    public void AddCurrency(CurrencyType type, int amount)
    {
        stats.ClampAndRecompute();
        amount = Mathf.Max(0, amount);

        int beforeSoft = stats.softCurrency;
        int beforeHard = stats.hardCurrency;

        if (type == CurrencyType.Soft) stats.softCurrency += amount;
        else stats.hardCurrency += amount;

        stats.ClampAndRecompute();

        if (beforeSoft != stats.softCurrency || beforeHard != stats.hardCurrency)
            OnCurrencyChanged?.Invoke(stats.softCurrency, stats.hardCurrency);
    }

    public bool SpendCurrency(CurrencyType type, int amount)
    {
        stats.ClampAndRecompute();
        amount = Mathf.Max(0, amount);

        if (type == CurrencyType.Soft)
        {
            if (stats.softCurrency < amount) return false;
            stats.softCurrency -= amount;
        }
        else
        {
            if (stats.hardCurrency < amount) return false;
            stats.hardCurrency -= amount;
        }

        stats.ClampAndRecompute();
        OnCurrencyChanged?.Invoke(stats.softCurrency, stats.hardCurrency);
        return true;
    }

    public void Save()
    {
        stats.ClampAndRecompute();
        string json = JsonUtility.ToJson(stats);
        PlayerPrefs.SetString(SaveKey, json);
        PlayerPrefs.Save();
    }

    public void Load()
    {
        if (!PlayerPrefs.HasKey(SaveKey)) return;
        string json = PlayerPrefs.GetString(SaveKey, "");
        if (string.IsNullOrEmpty(json)) return;

        try
        {
            stats = JsonUtility.FromJson<PlayerStats>(json) ?? new PlayerStats();
        }
        catch
        {
            stats = new PlayerStats();
        }

        stats.ClampAndRecompute();
    }

    void RaiseAll()
    {
        OnHealthChanged?.Invoke(stats.currentHealth, stats.maxHealth);
        OnCurrencyChanged?.Invoke(stats.softCurrency, stats.hardCurrency);
    }
}

[Serializable]
public class ShopItem
{
    public string id = "item_1";
    public string displayName = "Item";
    public CurrencyType currencyType = CurrencyType.Soft;

    [Header("Price")]
    public int basePrice = 100;
    public float priceGrowth = 1.15f;
    public int maxPurchases = 0;

    [Header("Effects")]
    public int addDamageFlat = 0;
    public float addDamageMultiplier = 0f;
    public int addMaxHealthFlat = 0;
    public int healOnPurchase = 0;

    [Header("Optional Level Gate")]
    public int requiredLevel = 1;

    [NonSerialized] public int purchasedCount = 0;

    public int GetPrice()
    {
        int n = Mathf.Max(0, purchasedCount);
        float p = basePrice * Mathf.Pow(Mathf.Max(1f, priceGrowth), n);
        return Mathf.Max(0, Mathf.RoundToInt(p));
    }

    public bool IsMaxed()
    {
        return maxPurchases > 0 && purchasedCount >= maxPurchases;
    }
}

public class ShopManager : MonoBehaviour
{
    public PlayerManager player;
    public ShopItem[] items;

    public event Action<string, int, CurrencyType> OnPurchaseSucceeded;
    public event Action<string> OnPurchaseFailed;

    const string ShopSaveKey = "SHOP_SAVE_V1";

    [Serializable]
    class ShopSave
    {
        public Entry[] entries;
        [Serializable] public class Entry { public string id; public int count; }
    }

    void Awake()
    {
        Load();
    }

    void OnApplicationQuit()
    {
        Save();
    }

    void OnApplicationPause(bool pause)
    {
        if (pause) Save();
    }

    public int GetPrice(string itemId)
    {
        var item = FindItem(itemId);
        if (item == null) return -1;
        return item.GetPrice();
    }

    public bool CanBuy(string itemId, out string reason)
    {
        reason = null;

        if (player == null || player.stats == null)
        {
            reason = "PlayerMissing";
            return false;
        }

        var item = FindItem(itemId);
        if (item == null)
        {
            reason = "ItemMissing";
            return false;
        }

        if (player.stats.level < Mathf.Max(1, item.requiredLevel))
        {
            reason = "LevelTooLow";
            return false;
        }

        if (item.IsMaxed())
        {
            reason = "Maxed";
            return false;
        }

        int price = item.GetPrice();
        if (price < 0)
        {
            reason = "InvalidPrice";
            return false;
        }

        if (item.currencyType == CurrencyType.Soft && player.stats.softCurrency < price)
        {
            reason = "NotEnoughSoft";
            return false;
        }

        if (item.currencyType == CurrencyType.Hard && player.stats.hardCurrency < price)
        {
            reason = "NotEnoughHard";
            return false;
        }

        return true;
    }

    public bool Buy(string itemId)
    {
        if (!CanBuy(itemId, out string reason))
        {
            OnPurchaseFailed?.Invoke(reason);
            return false;
        }

        var item = FindItem(itemId);
        int price = item.GetPrice();

        if (!player.SpendCurrency(item.currencyType, price))
        {
            OnPurchaseFailed?.Invoke("SpendFailed");
            return false;
        }

        ApplyItemEffects(item);
        item.purchasedCount++;

        OnPurchaseSucceeded?.Invoke(item.id, price, item.currencyType);
        return true;
    }

    void ApplyItemEffects(ShopItem item)
    {
        var s = player.stats;

        s.damageBonusFlat += Mathf.Max(0, item.addDamageFlat);
        s.damageBonusMultiplier += Mathf.Max(0f, item.addDamageMultiplier);

        s.healthBonusFlat += Mathf.Max(0, item.addMaxHealthFlat);

        s.ClampAndRecompute();

        if (item.healOnPurchase > 0)
            player.Heal(item.healOnPurchase);
        else
            player.Heal(0);
    }

    ShopItem FindItem(string id)
    {
        if (items == null) return null;
        for (int i = 0; i < items.Length; i++)
            if (items[i] != null && items[i].id == id)
                return items[i];
        return null;
    }

    public void Save()
    {
        if (items == null) return;

        var save = new ShopSave();
        save.entries = new ShopSave.Entry[items.Length];
        for (int i = 0; i < items.Length; i++)
        {
            save.entries[i] = new ShopSave.Entry
            {
                id = items[i] != null ? items[i].id : "",
                count = items[i] != null ? Mathf.Max(0, items[i].purchasedCount) : 0
            };
        }

        string json = JsonUtility.ToJson(save);
        PlayerPrefs.SetString(ShopSaveKey, json);
        PlayerPrefs.Save();
    }

    public void Load()
    {
        if (!PlayerPrefs.HasKey(ShopSaveKey)) return;
        string json = PlayerPrefs.GetString(ShopSaveKey, "");
        if (string.IsNullOrEmpty(json)) return;

        ShopSave save = null;
        try { save = JsonUtility.FromJson<ShopSave>(json); } catch { save = null; }
        if (save == null || save.entries == null || items == null) return;

        for (int i = 0; i < save.entries.Length; i++)
        {
            var e = save.entries[i];
            if (e == null) continue;
            var item = FindItem(e.id);
            if (item != null)
                item.purchasedCount = Mathf.Max(0, e.count);
        }
    }
}

