public class CombatExample : MonoBehaviour
{
    public PlayerManager player;
    public EnemyDummy enemy;

    public void PlayerAttack()
    {
        if (player == null || enemy == null) return;
        int dmg = player.CalculateOutgoingDamage(enemyDefense: enemy.defense, damageType: DamageType.Physical);
        enemy.TakeDamage(dmg);
    }

    public void EnemyAttackPlayer(int rawDamage)
    {
        if (player == null) return;
        player.ApplyIncomingDamage(rawDamage, armor: 0, damageType: DamageType.Physical);
    }
}